/**
 * This node replaces the logic that previously relied on 'Split Out' nodes.
 * It takes the raw response objects from the Merge node, extracts the
 * library items and the progress data, and calculates the unread books.
 */

const items = $input.all();
let allBooks = [];
let readLibraryIds = new Set();

// 1. Extract data from the input items
for (const item of items) {
  // Handle the Full Library response (expects a 'results' array)
  if (Array.isArray(item.json.results)) {
    allBooks.push(...item.json.results);
  }

  // Handle the User Details response (expects a 'mediaProgress' array)
  if (Array.isArray(item.json.mediaProgress)) {
    item.json.mediaProgress.forEach(progress => {
      if (progress.libraryItemId) {
        readLibraryIds.add(progress.libraryItemId);
      }
    });
  }
}

// 2. Safety check: If no books were found, return an empty array
if (allBooks.length === 0) {
  return [];
}

// 3. Filter: Keep only books whose ID is NOT in the readLibraryIds set
const unreadBooks = allBooks.filter(book => {
  // We compare the book's 'id' to the progress 'libraryItemId'
  return !readLibraryIds.has(book.id);
});

// 4. Map back to n8n item format (returning individual book objects)
return unreadBooks.map(book => ({ json: book }));

// Get configuration parameters
const config = $('Inject Secrets')
const maxRecommendations = config.first().json.recommendationCount

// Helper function to parse seriesName into array of objects
function parseSeries(seriesName) {
  if (!seriesName) return [];

  return seriesName
    .split(",")
    .map(s => s.trim())
    .map(entry => {
      // Match "<name> #<number>"
      const match = entry.match(/^(.*)\s+#(\d+(?:\.\d+)?)$/)
      if (!match) return null

      return { name: match[1].trim(), sequence: Number(match[2]) }
    })
}

// Summarize the data for the AI agent
const summary = $input.all().map(item => ({
  id: item.json.id,
  libraryId: item.json.libraryId,
  title: item.json.media?.metadata?.title || "",
  subtitle: item.json.media?.metadata?.subtitle || "",
  author: item.json.media?.metadata?.authors?.map(a => a.name).join(", ") || item.json.media?.metadata?.authorName || "",
  series: parseSeries(item.json.media?.metadata?.seriesName),
  rating: item.json.rating
}));

// Return summary as a single item containing the entire list.
return [{
  json: {
    books: summary,
    maxRecommendations: maxRecommendations
  }
}];

// Get configuration parameters
const config = $('Inject Secrets').first().json
const apiKey = config.apiKey
const baseUrl = config.baseUrl
const libraryId = config.libraryId

// Identify the recommendations playlist.
let playlistId = null;
try {
  // Access the raw results array from the first HTTP request in the playlist branch
  const playlistsResponse = $('Get Playlists List').first().json;
  const allPlaylists = playlistsResponse.results || [];

  // Search for the specific playlist by name
  const foundPlaylist = allPlaylists.find(item => item.name === '📖 Recommendations');

  if (foundPlaylist) {
    playlistId = foundPlaylist.id;
  }
} catch (e) {
  playlistId = null;
}

const data = $input.first().json.output[0].content[0].text;
const parsedData = JSON.parse(data);
const recommendations = parsedData.recommendations; 

const playlistItems = recommendations.map(item => ({
  libraryItemId: item.id,
  episodeId: null
}));

return {
    json: {
      apiKey: apiKey,
      baseUrl: baseUrl,
      items: playlistItems,
      libraryId: libraryId,
      playlistId: playlistId
    }
  };

// Get the results array from the single input item
const playlists = $input.first().json.results || [];
const enrichedLibraryItems = [];
const STAR_EMOJI = '⭐';

// Iterate through the playlists once
for (const playlist of playlists) {
  const name = playlist.name || '';

  // Count star emojis in the name (e.g., "⭐⭐" -> 2)
  const starCount = (name.match(new RegExp(STAR_EMOJI, 'g')) || []).length;

  // Verify the name is exactly the stars (prevents matching "⭐ My Favorites")
  const isExactStarMatch = starCount > 0 && name === STAR_EMOJI.repeat(starCount);

  if (isExactStarMatch) {
    if (playlist.items && Array.isArray(playlist.items)) {
      for (const entry of playlist.items) {
        // Only include items that have valid libraryItem data
        if (entry.libraryItem) {
          enrichedLibraryItems.push({
            json: {
              ...entry.libraryItem,
              rating: starCount
            }
          });
        }
      }
    }
  }
}

return enrichedLibraryItems;
